import{_ as a,a as n,b as i}from"./chunks/管理端登录界面.yuERlcJ6.js";import{_ as t,o as r,c as o,a2 as l}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Authenticatie en beheer van aanmeldapparaten","description":"","frontmatter":{},"headers":[],"relativePath":"nl-NL/Safety/authentication-and-login-devices.md","filePath":"nl-NL/Safety/authentication-and-login-devices.md","lastUpdated":1781962217000}'),d={name:"nl-NL/Safety/authentication-and-login-devices.md"};function s(p,e,h,g,u,c){return r(),o("div",null,[...e[0]||(e[0]=[l('<h1 id="authenticatie-en-beheer-van-aanmeldapparaten" tabindex="-1">Authenticatie en beheer van aanmeldapparaten <a class="header-anchor" href="#authenticatie-en-beheer-van-aanmeldapparaten" aria-label="Permalink to &quot;Authenticatie en beheer van aanmeldapparaten&quot;">​</a></h1><p><code>Authentication Management</code> en <code>Login Device Management</code> beschermen het ImgBed-beheer, de openbare uploadpagina en WebDAV-toegang.</p><p>Gebruik deze pagina om toegangsgegevens in te stellen, ingelogde apparaten te bekijken en oude sessies in te trekken wanneer dat nodig is.</p><h2 id="waar-je-dit-configureert" tabindex="-1">Waar je dit configureert <a class="header-anchor" href="#waar-je-dit-configureert" aria-label="Permalink to &quot;Waar je dit configureert&quot;">​</a></h2><p>Open het beheer en ga naar:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings</span></span></code></pre></div><p>De pagina bevat twee hoofdonderdelen:</p><ul><li>Authentication Management</li><li>Login Device Management</li></ul><p><img src="'+a+'" alt="Authenticatiebeheer" loading="lazy"></p><h2 id="wat-authentication-management-doet" tabindex="-1">Wat Authentication Management doet <a class="header-anchor" href="#wat-authentication-management-doet" aria-label="Permalink to &quot;Wat Authentication Management doet&quot;">​</a></h2><p>Authentication Management bewaart toegangsgegevens.</p><p>Er zijn twee typen:</p><ul><li>Authenticatie aan gebruikerszijde</li><li>Authenticatie aan beheerderszijde</li></ul><h2 id="authenticatie-aan-gebruikerszijde" tabindex="-1">Authenticatie aan gebruikerszijde <a class="header-anchor" href="#authenticatie-aan-gebruikerszijde" aria-label="Permalink to &quot;Authenticatie aan gebruikerszijde&quot;">​</a></h2><p>Authenticatie aan gebruikerszijde is het uploadwachtwoord.</p><p>Nadat je een uploadwachtwoord hebt ingesteld, moeten gewone bezoekers dit invullen voordat ze de uploadpagina kunnen gebruiken. Dit is handig wanneer je de openbare uploadpagina niet voor iedereen open wilt zetten.</p><p><img src="'+n+'" alt="Gebruikersloginpagina" loading="lazy"></p><h3 id="uploadwachtwoord-instellen" tabindex="-1">Uploadwachtwoord instellen <a class="header-anchor" href="#uploadwachtwoord-instellen" aria-label="Permalink to &quot;Uploadwachtwoord instellen&quot;">​</a></h3><p>Wanneer een uploadwachtwoord is ingesteld:</p><ul><li>Bezoekers moeten het wachtwoord invoeren voordat ze de uploadpagina gebruiken.</li><li>Uploaden is pas beschikbaar nadat het wachtwoord is geaccepteerd.</li><li>Als apparaatsessies aan gebruikerszijde zijn ingeschakeld, registreert ImgBed dat apparaat.</li></ul><p>Als je het uploadwachtwoord wijzigt, worden oude gebruikerssessies ongeldig. Bezoekers moeten het nieuwe wachtwoord opnieuw invoeren.</p><h2 id="authenticatie-aan-beheerderszijde" tabindex="-1">Authenticatie aan beheerderszijde <a class="header-anchor" href="#authenticatie-aan-beheerderszijde" aria-label="Permalink to &quot;Authenticatie aan beheerderszijde&quot;">​</a></h2><p>Beheerdersauthenticatie gebruikt een beheerdersnaam en wachtwoord.</p><p>Dit beschermt het beheerpaneel. Voor productiegebruik is het verstandig dit altijd in te stellen.</p><p><img src="'+i+'" alt="Beheerdersloginpagina" loading="lazy"></p><h3 id="beheerdersgegevens-instellen" tabindex="-1">Beheerdersgegevens instellen <a class="header-anchor" href="#beheerdersgegevens-instellen" aria-label="Permalink to &quot;Beheerdersgegevens instellen&quot;">​</a></h3><p>Wanneer een beheerdersnaam en wachtwoord zijn ingesteld:</p><ul><li>Het openen van het beheerpaneel vereist aanmelding.</li><li>Een succesvolle aanmelding maakt een apparaatrecord voor de beheerder aan.</li><li>Je kunt apparaten bekijken, opschonen of offline forceren in Login Device Management.</li></ul><p>Als je de beheerdersnaam of het wachtwoord wijzigt, worden oude beheerderssessies ongeldig. Je moet opnieuw inloggen.</p><h2 id="wat-login-device-management-doet" tabindex="-1">Wat Login Device Management doet <a class="header-anchor" href="#wat-login-device-management-doet" aria-label="Permalink to &quot;Wat Login Device Management doet&quot;">​</a></h2><p>Login Device Management toont apparaten die zijn ingelogd.</p><p>Het helpt je controleren:</p><ul><li>welke apparaten het beheerpaneel hebben gebruikt.</li><li>welke apparaten de uploadpagina aan gebruikerszijde hebben gebruikt.</li><li>welke WebDAV-clients verbinding hebben gemaakt.</li><li>of een apparaatsessie nog geldig is.</li><li>of oude apparaten offline moeten worden geforceerd.</li></ul><p>De pagina heeft drie tabbladen:</p><ul><li>Admin</li><li>User</li><li>WebDAV</li></ul><h2 id="globale-cookiebeveiliging" tabindex="-1">Globale cookiebeveiliging <a class="header-anchor" href="#globale-cookiebeveiliging" aria-label="Permalink to &quot;Globale cookiebeveiliging&quot;">​</a></h2><p>Bovenaan Login Device Management kun je het globale cookiegedrag instellen.</p><h3 id="levensduur-gebruikerscookie" tabindex="-1">Levensduur gebruikerscookie <a class="header-anchor" href="#levensduur-gebruikerscookie" aria-label="Permalink to &quot;Levensduur gebruikerscookie&quot;">​</a></h3><p>Bepaalt hoeveel dagen een login aan gebruikerszijde actief blijft.</p><p>Bijvoorbeeld: stel je dit in op 14 dagen, dan hoeven bezoekers meestal 14 dagen lang het uploadwachtwoord niet opnieuw in te voeren.</p><h3 id="levensduur-beheerderscookie" tabindex="-1">Levensduur beheerderscookie <a class="header-anchor" href="#levensduur-beheerderscookie" aria-label="Permalink to &quot;Levensduur beheerderscookie&quot;">​</a></h3><p>Bepaalt hoeveel dagen een beheerderslogin actief blijft.</p><p>Bijvoorbeeld: stel je dit in op 14 dagen, dan hoeven beheerders meestal 14 dagen lang niet opnieuw in te loggen.</p><h3 id="secure-mode" tabindex="-1">Secure Mode <a class="header-anchor" href="#secure-mode" aria-label="Permalink to &quot;Secure Mode&quot;">​</a></h3><p>Wanneer Secure mode is ingeschakeld, sturen browsers login-cookies alleen via HTTPS.</p><p>Schakel dit in voor productiesites met HTTPS. Schakel het niet in voor lokale HTTP-tests, anders kun je gedrag zien als &quot;login gelukt, maar na verversen ben ik weer uitgelogd&quot;.</p><h2 id="beheerdersapparaten" tabindex="-1">Beheerdersapparaten <a class="header-anchor" href="#beheerdersapparaten" aria-label="Permalink to &quot;Beheerdersapparaten&quot;">​</a></h2><p>Het tabblad Admin toont apparaten die zijn ingelogd op het beheerpaneel.</p><p>Apparaatrecords verschijnen pas nadat beheerdersgegevens zijn ingesteld en het beheerpaneel via login is geopend.</p><p>Elke apparaatkaart kan tonen:</p><ul><li>apparaat- en browserinformatie</li><li>IP van eerste login</li><li>IP van laatste activiteit</li><li>inlogtijd</li><li>tijd van laatste activiteit</li><li>verloopdatum</li><li>huidige status</li></ul><p>Zie je een onbekend apparaat, gebruik dan <code>Force Offline</code> om de sessie ongeldig te maken.</p><h2 id="oude-apparaten-opschonen" tabindex="-1">Oude apparaten opschonen <a class="header-anchor" href="#oude-apparaten-opschonen" aria-label="Permalink to &quot;Oude apparaten opschonen&quot;">​</a></h2><p><code>Clean Up Old Devices</code> verwijdert oude loginrecords in het huidige tabblad in één keer.</p><p>Gebruik dit wanneer je vermoedt dat oude sessies nog actief zijn op andere apparaten.</p><h2 id="offline-forceren" tabindex="-1">Offline forceren <a class="header-anchor" href="#offline-forceren" aria-label="Permalink to &quot;Offline forceren&quot;">​</a></h2><p><code>Force Offline</code> maakt één apparaatsessie ongeldig.</p><p>Daarna geldt:</p><ul><li>beheerdersapparaten moeten opnieuw inloggen.</li><li>apparaten aan gebruikerszijde moeten het uploadwachtwoord opnieuw invoeren.</li><li>WebDAV-clients moeten opnieuw authenticeren.</li></ul><p>Verlopen of ongeldige apparaten kunnen ook worden verwijderd.</p><h2 id="huidig-apparaat-uitloggen" tabindex="-1">Huidig apparaat uitloggen <a class="header-anchor" href="#huidig-apparaat-uitloggen" aria-label="Permalink to &quot;Huidig apparaat uitloggen&quot;">​</a></h2><p>De kaart van het huidige apparaat is gemarkeerd als <code>Current Device</code>.</p><p>Na uitloggen van het huidige apparaat:</p><ul><li>wordt de huidige beheerderssessie afgesloten.</li><li>wordt de huidige gebruikerssessie afgesloten.</li></ul><p>Je moet opnieuw inloggen voordat je dat deel verder kunt gebruiken.</p>',65)])])}const v=t(d,[["render",s]]);export{m as __pageData,v as default};
